mapper.update:
UPDATE loan_application 
SET status = #{status}, audit_time = #{auditTime}, update_time = NOW() 
WHERE id = #{id}

mapper.select:
SELECT a.*, u.username, p.real_name as realName, pr.name as productName FROM loan_application a LEFT JOIN sys_user u ON a.user_id = u.id LEFT JOIN user_profile p ON a.user_id = p.user_id LEFT JOIN loan_product pr ON a.product_id = pr.id
AND a.user_id = #{userId}
ORDER BY a.create_time DESC
